import React, { useState, useEffect, useContext } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';
import { CartContext } from '../context/CartContext';

const BASE_URL = 'http://localhost:5000';

const Shop = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const { addToCart } = useContext(CartContext);

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const { data } = await api.get('/products');
        setProducts(data);
      } catch (error) {
        console.error('Error fetching products', error);
      } finally {
        setLoading(false);
      }
    };

    fetchProducts();
  }, []);

  const handleAddToCart = (e, product) => {
    e.preventDefault();
    e.stopPropagation();
    addToCart(product);
  };

  return (
    <div className="container">
      <h1 className="page-title">Collection</h1>
      {loading ? (
        <p>Loading...</p>
      ) : products.length === 0 ? (
        <p style={{ textAlign: 'center', color: 'var(--color-gray-dark)' }}>No products available yet.</p>
      ) : (
        <div className="product-grid">
          {products.map((product) => (
            <div key={product._id} className="product-card">
              <Link to={`/product/${product._id}`}>
                <div
                  className="product-image"
                  style={{
                    backgroundImage: product.imageUrl ? `url(${BASE_URL}${product.imageUrl})` : 'none',
                    backgroundSize: 'cover',
                    backgroundPosition: 'center'
                  }}
                >
                  {product.featured && (
                    <span style={{
                      position: 'absolute', top: 12, left: 12,
                      background: 'var(--color-black)', color: 'var(--color-white)',
                      fontSize: '0.7rem', textTransform: 'uppercase', letterSpacing: '1px',
                      padding: '4px 10px',
                    }}>Featured</span>
                  )}
                  {product.luxuryLabel && (
                    <span style={{
                      position: 'absolute', bottom: 12, left: 12,
                      background: 'rgba(0,0,0,0.7)', color: 'gold',
                      fontSize: '0.65rem', textTransform: 'uppercase', letterSpacing: '1.5px',
                      padding: '3px 8px', backdropFilter: 'blur(4px)',
                    }}>{product.luxuryLabel}</span>
                  )}
                </div>
              </Link>
              <div className="product-info">
                <Link to={`/product/${product._id}`}>
                  <span className="product-name">{product.name}</span>
                </Link>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  {product.oldPrice && (
                    <span style={{ textDecoration: 'line-through', color: 'var(--color-gray-dark)', fontSize: '0.85rem' }}>
                      ${product.oldPrice}
                    </span>
                  )}
                  <span className="product-price">${product.price}</span>
                </div>
              </div>
              <button
                className="btn"
                style={{ width: '100%', marginTop: '10px', fontSize: '0.8rem' }}
                onClick={(e) => handleAddToCart(e, product)}
              >
                Add to Cart
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Shop;
